public int removeDuplicates(int[] nums) {
    if (nums.length == 0) return 0;

    int k = 1; // slow pointer: next write position (first element is always unique)

    for (int i = 1; i < nums.length; i++) { // fast pointer
        if (nums[i] != nums[k - 1]) {
            nums[k] = nums[i];
            k++;
        }
    }
    return k;
}
