public void sortColors(int[] nums) {
    int low = 0, mid = 0, high = nums.length - 1;

    while (mid <= high) {
        if (nums[mid] == 0) {
            // Swap with low region
            int temp = nums[low];
            nums[low] = nums[mid];
            nums[mid] = temp;
            low++;
            mid++;
        } else if (nums[mid] == 1) {
            mid++; // already in correct region
        } else { // nums[mid] == 2
            // Swap with high region
            int temp = nums[mid];
            nums[mid] = nums[high];
            nums[high] = temp;
            high--;
            // Don't increment mid: nums[mid] is now unprocessed
        }
    }
}
